type PaymentStatus = "pending" | "processing" | "paid" | "failed" | "refunded";

interface Payment {
  id: string;
  amount: number;
  status: PaymentStatus;
  customerId: number;
}

function getStatusLabel(status: PaymentStatus): string {
  const labels: Record<PaymentStatus, string> = {
    pending:    "⏳ Awaiting payment",
    processing: "⚙️  Processing",
    paid:       "✅ Paid",
    failed:     "❌ Payment failed",
    refunded:   "↩️  Refunded",
  };
  return labels[status];
}

const payments: Payment[] = [
  { id: "PAY-001", amount: 299, status: "paid",       customerId: 1 },
  { id: "PAY-002", amount: 89,  status: "pending",    customerId: 2 },
  { id: "PAY-003", amount: 149, status: "failed",     customerId: 3 },
  { id: "PAY-004", amount: 499, status: "processing", customerId: 4 },
];

for (const p of payments) {
  console.log(`${p.id} ($${p.amount}): ${getStatusLabel(p.status)}`);
}

type Shape =
  | { kind: "circle";    radius: number }
  | { kind: "rectangle"; width: number; height: number }
  | { kind: "triangle";  base: number;  height: number };

function area(shape: Shape): number {
  switch (shape.kind) {
    case "circle":    return Math.PI * shape.radius ** 2;
    case "rectangle": return shape.width * shape.height;
    case "triangle":  return 0.5 * shape.base * shape.height;
    // TypeScript ensures all cases are handled
  }
}

function describe(shape: Shape): string {
  switch (shape.kind) {
    case "circle":    return `Circle (r=${shape.radius})`;
    case "rectangle": return `Rectangle (${shape.width}×${shape.height})`;
    case "triangle":  return `Triangle (b=${shape.base}, h=${shape.height})`;
  }
}

const shapes: Shape[] = [
  { kind: "circle",    radius: 5 },
  { kind: "rectangle", width: 4, height: 6 },
  { kind: "triangle",  base: 8, height: 3 },
];

for (const s of shapes) {
  console.log(`${describe(s)}: area = ${area(s).toFixed(2)}`);
}

type WithAudit = {
  createdAt: string;
  updatedAt: string;
  createdBy: string;
};

type WithSoftDelete = {
  deletedAt: string | null;
  isDeleted: boolean;
};

interface UserEntity {
  id: number;
  name: string;
  email: string;
  role: string;
}

// Combine all three contracts
type AuditableUser = UserEntity & WithAudit & WithSoftDelete;

function formatAuditLog(entity: AuditableUser): string {
  const status = entity.isDeleted ? "DELETED" : "ACTIVE";
  return `[${status}] ${entity.name} | Created by ${entity.createdBy} on ${entity.createdAt}`;
}

const users: AuditableUser[] = [
  { id: 1, name: "Alice", email: "alice@co.com", role: "admin",
    createdAt: "2022-01-15", updatedAt: "2024-01-01", createdBy: "system",
    deletedAt: null, isDeleted: false },
  { id: 2, name: "Bob",   email: "bob@co.com",   role: "editor",
    createdAt: "2022-06-20", updatedAt: "2023-11-01", createdBy: "alice",
    deletedAt: "2024-01-01", isDeleted: true },
];

for (const u of users) {
  console.log(formatAuditLog(u));
}
